INSERT INTO news (title, summary, content, image_url, published_at)
VALUES ('Inauguración de Comedor Comunitario en Quito', 'Un espacio integral que brindará más de 200 almuerzos diarios a familias en situación de vulnerabilidad en el sector de Solanda.', 'Este martes abrió sus puertas el nuevo punto de atención de Ecuador Comparte en el sur de Quito.', 'https://images.unsplash.com/photo-1593113598332-cd288d649433?q=80&w=600', '2026-05-15 14:00:00');

INSERT INTO news (title, summary, content, image_url, published_at)
VALUES ('Gran Colecta Nacional de Víveres en Guayaquil', 'Convocatoria abierta para recolectar alimentos no perecederos en los principales centros comerciales de la ciudad.', 'La delegación de Guayaquil Comparte anunció el despliegue de voluntarios.', 'https://images.unsplash.com/photo-1544620347-c4fd4a3d5957?q=80&w=600', '2026-05-18 09:15:30');